  ('disabled-64311456-moex-00116', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '甲為導遊，於帶領觀光客至風景特定區觀光時，趁機盜挖風景特定區之礦 石，為主管機關發現，移送檢察官偵查後起訴。該主管機關於下列何種情 形，不得再依發展觀光條例予以裁處罰鍰？', '["法院判決有罪確定", "法院判決無罪確定", "法院判決免訴確定", "法院判決有罪但諭知緩刑確定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00117', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '某餐廳因長期違法排放大量空氣污染物，主管機關命其停止營業；該餐廳 不從，仍繼續營業。主管機關遂對之實施斷水斷電措施。此斷水斷電措施， 屬於行政執行法中何種類型之方法？', '["代履行", "直接強制", "即時強制", "間接強制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00118', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政執行之拘提及管收，下列敘述何者正確？', '["義務人或其他依法得管收之人有懷胎6月以上或生產後3月未滿者，不 得管收", "自管收之日起算，管收期限不得逾2個月", "法院為拘提之裁定後，應將拘票交由司法警察機關派司法警察執行拘提", "行政執行處應隨時提詢被管收人，每月不得少於3次"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00119', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '行政執行機關就公法上金錢義務人之財產進行強制執行，義務人認為執行 名義並未合法送達，執行行為違反法定程序，其應採何種權利救濟手段？', '["提起訴願", "聲請假處分", "聲明異議", "聲請定暫時狀態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00120', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依行政程序法規定，關於送達之敘述，下列何者正確？', '["內容對人民權利義務有重大影響之文書，應由行政機關之承辦人員自行 為送達", "應受送達人之法定代理人有2人以上時，應同時向所有法定代理人為送達", "由郵政機關為送達者，原則上應以一般郵遞方式為之，並以郵務人員為 送達人", "行政機關交由郵政機關為送達者，不得於星期日或其他休息日，或日沒 後為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00121', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政程序法規定之適用，下列敘述何者正確？', '["司法機關之行政行為不適用行政程序法之實體規定", "犯罪矯正機關為達收容目的所為之行為適用行政程序法之實體規定", "公務員身分產生之公法上財產請求權不適用行政程序法之規定", "行政機關就私權爭執所為之行政裁決適用行政程序法之程序規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00122', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依行政程序法，關於非書面行政處分，下列敘述何者錯誤？', '["法律未規定何種行政處分應以書面為之時，處分機關有形式選擇自由", "處分機關作成非書面行政處分時，應以適當方法通知相對人、已知之利 害關係人或使其知悉", "處分機關以言詞作成處分時，如相對人有正當理由，可要求處分機關作 成書面", "因相對人要求，處分機關將言詞作成之處分作成書面後，該處分之效力 自書面送達後之次日發生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
